CREATE TABLE `training_courses` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `code` varchar(20) NOT NULL,
  `training_type` enum('External','Internal') NOT NULL DEFAULT 'External',
  `title` text NOT NULL,
  `company` varchar(10) DEFAULT 'FJB',
  `training_date` date DEFAULT NULL,
  `venue` varchar(300) DEFAULT NULL,
  `consultant` varchar(200) DEFAULT NULL,
  `cost_per_pax` decimal(10,2) DEFAULT NULL,
  `claimable` varchar(50) DEFAULT NULL,
  `doc_ref` varchar(50) DEFAULT 'Doc.No.213',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `duration` varchar(100) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `code` (`code`)
) ENGINE=InnoDB AUTO_INCREMENT=1971 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
